        "pubDate": "2026-07-15T07:57:15+00:00",
        "link": "https://newsonair.gov.in/12th-brics-labour-and-employment-ministers-meeting-begins-in-hyderabad/",
        "image_url": "https://newsonair.gov.in/wp-content/uploads/2026/07/p-1.jpg",
